mapper.select:
SELECT COUNT(*)
  FROM users
 WHERE login_id = #{loginId}

   AND id <> #{excludeUserId}

SELECT p.*, u.login_id, u.phone_number, u.phone_verified FROM user_profile p INNER JOIN users u ON u.id = p.user_id
AND (u.email LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%') OR p.desired_job LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.updated_at DESC LIMIT #{limit}
